#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x < y) - (x > y); // descending order
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        long long H;
        scanf("%d %d %lld", &N, &M, &H);
        long long *cars = (long long *)malloc(N * sizeof(long long));
        long long *energies = (long long *)malloc(M * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &cars[i]);
        for (int i = 0; i < M; ++i) {
            long long b; scanf("%lld", &b);
            energies[i] = b * H; // total energy each outlet can provide
        }
        qsort(cars, N, sizeof(long long), cmp_desc);
        qsort(energies, M, sizeof(long long), cmp_desc);
        long long total = 0;
        int limit = N < M ? N : M;
        for (int i = 0; i < limit; ++i) {
            total += (cars[i] < energies[i]) ? cars[i] : energies[i];
        }
        printf("%lld\n", total);
        free(cars);
        free(energies);
    }
    return 0;
}

