        for (int i = 0; i < M; ++i) {
            long long b; cin >> b;
            energies[i] = b * H;
        }
        sort(cars.rbegin(), cars.rend());
        sort(energies.rbegin(), energies.rend());
        long long ans = 0;
        int limit = min(N, M);
        for (int i = 0; i < limit; ++i) ans += min(cars[i], energies[i]);
        cout << ans << '\n';
    }
    return 0;
}

