const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let results = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const M = data[idx++];
  const H = data[idx++];
  const cars = data.slice(idx, idx + N); idx += N;
  const outlets = data.slice(idx, idx + M); idx += M;
  const energies = outlets.map(b => b * H);
  cars.sort((a, b) => b - a);
  energies.sort((a, b) => b - a);
  const limit = Math.min(cars.length, energies.length);
  let total = 0;
  for (let i = 0; i < limit; i++) {
    total += cars[i] < energies[i] ? cars[i] : energies[i];
  }
  results.push(String(total));
}
console.log(results.join('\n'));
